#include <unordered_map>
#include <algorithm>

long long solve(std::vector<long long> nums, long long k) {
    std::unordered_map<long long, long long> prefix_mod;
    prefix_mod[0] = 0; // Initialize with 0 mod k
    long long current_mod = 0;
    long long min_sum = 0;

    for (long long num : nums) {
        current_mod = (current_mod + num) % k;
        if (prefix_mod.find(current_mod) != prefix_mod.end()) {
            // We can remove the subarray between the previous prefix and current prefix
            min_sum = std::min(min_sum, current_mod);
        } else {
            prefix_mod[current_mod] = current_mod;
        }
    }

    return min_sum;
}

